UPDATE words SET example_en_2 = 'The artist acknowledged the influence of traditional crafts on her work.', example_ko_2 = '그 예술가는 전통 공예가 자신의 작품에 미친 영향을 인정했어요.', example_en_3 = 'His music has had a lasting influence on younger artists.', example_ko_3 = '그의 음악은 젊은 예술가들에게 지속적인 영향을 미쳤어요.', example_en_4 = 'Which director has had the greatest influence on your work?', example_ko_4 = '어떤 감독이 당신의 작품에 가장 큰 영향을 미쳤나요?', example_en_5 = 'Cultural exchange is a major influence on modern art.', example_ko_5 = '문화 교류는 현대 미술에 중요한 영향을 미치고 있어요.' WHERE id = 'w_culture_B1_20';

UPDATE words SET example_en_2 = 'Impressionism was part of a broader artistic movement in France.', example_ko_2 = '인상주의는 프랑스의 더 넓은 예술 운동의 일부였어요.', example_en_3 = 'She wrote her thesis on the Romantic movement in literature.', example_ko_3 = '그녀는 문학의 낭만주의 운동에 관한 논문을 썼어요.', example_en_4 = 'The movement challenged conventions of the time.', example_ko_4 = '그 운동은 당시의 관습에 도전했어요.', example_en_5 = 'The feminist art movement changed the gallery world.', example_ko_5 = '페미니스트 예술 운동은 갤러리 세계를 바꿨어요.' WHERE id = 'w_culture_B1_21';

UPDATE words SET example_en_2 = 'We joined an exhibition tour led by the artist herself.', example_ko_2 = '저희는 예술가 본인이 안내하는 전시 투어에 참여했어요.', example_en_3 = 'The school organised an exhibition tour for the students.', example_ko_3 = '학교는 학생들을 위해 전시 투어를 마련했어요.', example_en_4 = 'The exhibition tour helps visitors engage more deeply with the art.', example_ko_4 = '전시 투어는 방문객들이 예술과 더 깊이 교감하는 데 도움을 줘요.', example_en_5 = 'Book an exhibition tour online before you visit.', example_ko_5 = '방문 전에 온라인으로 전시 투어를 예약해보세요.' WHERE id = 'w_culture_B1_22';

UPDATE words SET example_en_2 = 'She hummed the melody as she walked home.', example_ko_2 = '그녀는 집에 걸어가면서 멜로디를 흥얼거렸어요.', example_en_3 = 'The melody is simple but deeply moving.', example_ko_3 = '그 멜로디는 단순하지만 깊이 감동적이에요.', example_en_4 = 'He composed the melody in just one afternoon.', example_ko_4 = '그는 단 하나의 오후에 멜로디를 작곡했어요.', example_en_5 = 'The melody was inspired by a Korean lullaby.', example_ko_5 = '그 멜로디는 한국 자장가에서 영감을 받았어요.' WHERE id = 'w_culture_B1_23';

UPDATE words SET example_en_2 = 'The whole crowd sang the chorus together.', example_ko_2 = '관중 모두가 함께 후렴구를 불렀어요.', example_en_3 = 'He wrote the chorus in just a few minutes.', example_ko_3 = '그는 단 몇 분 만에 후렴구를 썼어요.', example_en_4 = 'The chorus is the most memorable part of the song.', example_ko_4 = '후렴구는 노래에서 가장 기억에 남는 부분이에요.', example_en_5 = 'The chorus gets louder each time it repeats.', example_ko_5 = '후렴구는 반복될 때마다 더 크게 들려요.' WHERE id = 'w_culture_B1_24';

UPDATE words SET example_en_2 = 'The exhibition was a tribute to the artist''s long career.', example_ko_2 = '그 전시회는 예술가의 오랜 경력에 대한 헌정이었어요.', example_en_3 = 'She sang a tribute song at the memorial concert.', example_ko_3 = '그녀는 추모 콘서트에서 헌정곡을 불렀어요.', example_en_4 = 'The film is a tribute to the courage of artists under censorship.', example_ko_4 = '그 영화는 검열하에 놓인 예술가들의 용기에 대한 헌정이에요.', example_en_5 = 'Fans gathered to pay tribute to the legendary musician.', example_ko_5 = '팬들이 전설적인 음악가에게 경의를 표하기 위해 모였어요.' WHERE id = 'w_culture_B1_25';

UPDATE words SET example_en_2 = 'The two galleries announced a collaboration on a new project.', example_ko_2 = '두 갤러리는 새로운 프로젝트에서의 협업을 발표했어요.', example_en_3 = 'Their collaboration produced some of the finest music of the decade.', example_ko_3 = '그들의 협업은 10년 동안 최고의 음악 중 일부를 탄생시켰어요.', example_en_4 = 'She values collaboration over working alone.', example_ko_4 = '그녀는 혼자 작업하는 것보다 협업을 더 중요하게 여겨요.', example_en_5 = 'International collaboration can push art in exciting new directions.', example_ko_5 = '국제 협업은 예술을 흥미로운 새로운 방향으로 이끌 수 있어요.' WHERE id = 'w_culture_B1_26';

UPDATE words SET example_en_2 = 'The venue was transformed for the immersive art event.', example_ko_2 = '공연 장소는 몰입형 예술 행사를 위해 변형됐어요.', example_en_3 = 'She prefers small, intimate venues to large halls.', example_ko_3 = '그녀는 대형 홀보다 작고 친밀한 공연 장소를 선호해요.', example_en_4 = 'The venue has hosted many legendary concerts.', example_ko_4 = '그 공연 장소는 많은 전설적인 콘서트를 개최했어요.', example_en_5 = 'We arrived early to get good seats at the venue.', example_ko_5 = '저희는 공연 장소에서 좋은 자리를 잡기 위해 일찍 도착했어요.' WHERE id = 'w_culture_B1_27';

UPDATE words SET example_en_2 = 'He played an acoustic set for a small audience.', example_ko_2 = '그는 소규모 관객을 위해 어쿠스틱 세트를 연주했어요.', example_en_3 = 'The acoustic version of the song is even better than the original.', example_ko_3 = '그 노래의 어쿠스틱 버전이 원곡보다 더 좋아요.', example_en_4 = 'The hall had excellent acoustic qualities.', example_ko_4 = '그 홀은 훌륭한 음향 품질을 갖추고 있었어요.', example_en_5 = 'She released an acoustic EP to accompany the album.', example_ko_5 = '그녀는 앨범과 함께 어쿠스틱 EP를 발매했어요.' WHERE id = 'w_culture_B1_28';

UPDATE words SET example_en_2 = 'The gallery showcases new artists every month.', example_ko_2 = '그 갤러리는 매달 새로운 예술가들을 선보여요.', example_en_3 = 'The project showcases the diversity of Korean contemporary art.', example_ko_3 = '그 프로젝트는 한국 현대 미술의 다양성을 선보여요.', example_en_4 = 'She was chosen to showcase her work at the national fair.', example_ko_4 = '그녀는 국가 박람회에서 작품을 선보이도록 선정됐어요.', example_en_5 = 'The concert was designed to showcase emerging performers.', example_ko_5 = '그 콘서트는 신흥 공연자들을 선보이기 위해 기획됐어요.' WHERE id = 'w_culture_B1_29';

UPDATE words SET example_en_2 = 'The revival brought in audiences who had never seen the original.', example_ko_2 = '재현은 원작을 본 적 없는 관객들을 불러모았어요.', example_en_3 = 'The revival production stayed faithful to the original script.', example_ko_3 = '재현 작품은 원래 대본에 충실했어요.', example_en_4 = 'There has been a revival of interest in classical painting.', example_ko_4 = '고전 회화에 대한 관심이 부활하고 있어요.', example_en_5 = 'The Broadway revival was even better than the first production.', example_ko_5 = '브로드웨이 재현 공연은 처음 작품보다 더 좋았어요.' WHERE id = 'w_culture_B1_30';

UPDATE words SET example_en_2 = 'The dramatic lighting made the painting look even more powerful.', example_ko_2 = '극적인 조명이 그림을 더욱 강렬하게 보이게 했어요.', example_en_3 = 'She delivered a dramatic monologue that silenced the room.', example_ko_3 = '그녀는 방을 조용하게 만드는 극적인 독백을 했어요.', example_en_4 = 'The film''s dramatic final scene stayed with me for days.', example_ko_4 = '그 영화의 극적인 마지막 장면이 며칠 동안 머릿속에 남아 있었어요.', example_en_5 = 'The dramatic shift in style surprised even his fans.', example_ko_5 = '스타일의 극적인 변화는 그의 팬들도 놀라게 했어요.' WHERE id = 'w_culture_B1_31';

UPDATE words SET example_en_2 = 'She was invited to improvise a piece at the opening.', example_ko_2 = '그녀는 개막식에서 즉흥 연주를 해달라는 초대를 받았어요.', example_en_3 = 'The band would often improvise a new arrangement on stage.', example_ko_3 = '그 밴드는 무대에서 종종 새로운 편곡을 즉흥으로 연주하곤 했어요.', example_en_4 = 'Being able to improvise is a key skill for any performer.', example_ko_4 = '즉흥 연주를 할 수 있는 능력은 모든 공연자에게 핵심적인 기술이에요.', example_en_5 = 'He improvised a song using only three chords.', example_ko_5 = '그는 단 세 개의 코드만으로 즉흥곡을 연주했어요.' WHERE id = 'w_culture_B1_32';

UPDATE words SET example_en_2 = 'The gallery opening was attended by over two hundred guests.', example_ko_2 = '갤러리 오프닝에는 이백 명이 넘는 손님이 참석했어요.', example_en_3 = 'She wore a striking outfit to the gallery opening.', example_ko_3 = '그녀는 갤러리 오프닝에 눈에 띄는 의상을 입고 갔어요.', example_en_4 = 'The gallery opening is always a chance to meet new artists.', example_ko_4 = '갤러리 오프닝은 항상 새로운 예술가들을 만날 수 있는 기회예요.', example_en_5 = 'Are you going to the gallery opening this Saturday?', example_ko_5 = '이번 토요일 갤러리 오프닝에 가실 건가요?' WHERE id = 'w_culture_B1_33';

UPDATE words SET example_en_2 = 'She performed a solo on the cello during the concert.', example_ko_2 = '그녀는 콘서트에서 첼로 독주를 연주했어요.', example_en_3 = 'His solo career took off after leaving the band.', example_ko_3 = '그는 밴드를 떠난 후 솔로 활동을 시작했어요.', example_en_4 = 'The dance solo in the second act was breathtaking.', example_ko_4 = '2막의 댄스 솔로는 숨막히게 아름다웠어요.', example_en_5 = 'He felt nervous performing a solo for the first time.', example_ko_5 = '그는 처음으로 독주를 연주할 때 긴장됐어요.' WHERE id = 'w_culture_B1_34';

