UPDATE words SET example_en_2 = 'The course introduced students to semiotics through everyday images.', example_ko_2 = '그 수업은 일상적인 이미지를 통해 학생들에게 기호학을 소개했어요.', example_en_3 = 'Semiotics shows how meaning is constructed rather than given.', example_ko_3 = '기호학은 의미가 주어지는 것이 아니라 구성되는 방식을 보여줘요.', example_en_4 = 'She applied semiotics to analyse advertising imagery.', example_ko_4 = '그녀는 기호학을 광고 이미지 분석에 적용했어요.', example_en_5 = 'Semiotics is essential for understanding how films communicate meaning.', example_ko_5 = '기호학은 영화가 어떻게 의미를 전달하는지 이해하는 데 필수적이에요.' WHERE id = 'w_culture_C1_01';

UPDATE words SET example_en_2 = 'The seminar explored hermeneutics as a method of reading artworks.', example_ko_2 = '그 세미나는 예술 작품 읽기 방법으로서의 해석학을 탐구했어요.', example_en_3 = 'Hermeneutics reminds us that interpretation is always historically situated.', example_ko_3 = '해석학은 해석이 항상 역사적으로 상황에 처해 있음을 상기시켜줘요.', example_en_4 = 'Her thesis draws on hermeneutics to analyse folk songs.', example_ko_4 = '그녀의 논문은 민요를 분석하기 위해 해석학을 활용해요.', example_en_5 = 'Hermeneutics is concerned with the conditions under which understanding occurs.', example_ko_5 = '해석학은 이해가 일어나는 조건에 관심을 기울여요.' WHERE id = 'w_culture_C1_02';

UPDATE words SET example_en_2 = 'Deconstruction reveals the hidden assumptions embedded in a text.', example_ko_2 = '해체주의는 텍스트에 내재된 숨겨진 가정을 드러내요.', example_en_3 = 'She used deconstruction to expose contradictions in the film''s ideology.', example_ko_3 = '그녀는 해체주의를 사용해 영화의 이데올로기 속의 모순을 드러냈어요.', example_en_4 = 'Deconstruction does not destroy meaning; it multiplies it.', example_ko_4 = '해체주의는 의미를 파괴하지 않고 오히려 의미를 증가시켜요.', example_en_5 = 'The artist employs deconstruction as both a method and a theme.', example_ko_5 = '그 예술가는 해체주의를 방법론과 주제 모두로 활용해요.' WHERE id = 'w_culture_C1_03';

UPDATE words SET example_en_2 = 'The philosopher applied phenomenology to the experience of listening to music.', example_ko_2 = '그 철학자는 음악 듣기 경험에 현상학을 적용했어요.', example_en_3 = 'Phenomenology shifts attention from the artwork itself to the act of perceiving it.', example_ko_3 = '현상학은 관심을 예술 작품 자체에서 그것을 인식하는 행위로 이동시켜요.', example_en_4 = 'She uses phenomenology to understand how spectators engage with installation art.', example_ko_4 = '그녀는 현상학을 사용해 관람객이 설치 미술과 어떻게 교감하는지 이해해요.', example_en_5 = 'Phenomenology insists that bodily experience shapes aesthetic perception.', example_ko_5 = '현상학은 신체적 경험이 미학적 인식을 형성한다고 주장해요.' WHERE id = 'w_culture_C1_04';

UPDATE words SET example_en_2 = 'Structuralism analyses cultural phenomena by identifying underlying patterns.', example_ko_2 = '구조주의는 내재된 패턴을 식별함으로써 문화 현상을 분석해요.', example_en_3 = 'She found structuralism too rigid to account for historical change.', example_ko_3 = '그녀는 구조주의가 역사적 변화를 설명하기에 너무 경직돼 있다고 느꼈어요.', example_en_4 = 'Lévi-Strauss applied structuralism to the study of myth.', example_ko_4 = '레비스트로스는 구조주의를 신화 연구에 적용했어요.', example_en_5 = 'Structuralism transformed linguistics and subsequently art criticism.', example_ko_5 = '구조주의는 언어학을 변화시켰고 이후에 미술 비평도 변화시켰어요.' WHERE id = 'w_culture_C1_05';

UPDATE words SET example_en_2 = 'The installation explores intertextuality between cinema and painting.', example_ko_2 = '그 설치물은 영화와 회화 사이의 상호텍스트성을 탐구해요.', example_en_3 = 'Intertextuality shows that no text exists in isolation.', example_ko_3 = '상호텍스트성은 어떤 텍스트도 독립적으로 존재하지 않음을 보여줘요.', example_en_4 = 'Her lecture traced the intertextuality between Korean cinema and French New Wave.', example_ko_4 = '그녀의 강의는 한국 영화와 프랑스 누벨바그 사이의 상호텍스트성을 추적했어요.', example_en_5 = 'Intertextuality is fundamental to understanding postmodern literary works.', example_ko_5 = '상호텍스트성은 포스트모던 문학 작품을 이해하는 데 근본적이에요.' WHERE id = 'w_culture_C1_06';

UPDATE words SET example_en_2 = 'The dialectic between tradition and innovation drives artistic progress.', example_ko_2 = '전통과 혁신 사이의 변증법이 예술적 진보를 이끌어요.', example_en_3 = 'Hegel''s dialectic is applied here to analyse the history of art movements.', example_ko_3 = '헤겔의 변증법이 여기에서 예술 운동의 역사를 분석하는 데 적용됐어요.', example_en_4 = 'The play stages the dialectic between individual freedom and social constraint.', example_ko_4 = '그 연극은 개인의 자유와 사회적 제약 사이의 변증법을 무대 위에 올려요.', example_en_5 = 'Her thesis examines the dialectic of influence between two great painters.', example_ko_5 = '그녀의 논문은 두 위대한 화가 사이의 영향의 변증법을 검토해요.' WHERE id = 'w_culture_C1_07';

UPDATE words SET example_en_2 = 'Plato''s concept of mimesis sees art as a copy of a copy of reality.', example_ko_2 = '플라톤의 미메시스 개념은 예술을 현실의 사본의 사본으로 봐요.', example_en_3 = 'Mimesis in theatre asks how closely performance can mirror lived experience.', example_ko_3 = '연극에서의 미메시스는 공연이 실제 경험을 얼마나 가깝게 반영할 수 있는지 묻는 거예요.', example_en_4 = 'Modernist art often abandoned mimesis in favour of abstraction.', example_ko_4 = '모더니스트 예술은 종종 추상을 위해 미메시스를 포기했어요.', example_en_5 = 'The debate over mimesis and expression has shaped Western aesthetics for centuries.', example_ko_5 = '미메시스와 표현에 대한 논쟁은 수 세기 동안 서양 미학을 형성해왔어요.' WHERE id = 'w_culture_C1_08';

UPDATE words SET example_en_2 = 'The documentary produced catharsis by giving voice to survivors.', example_ko_2 = '그 다큐멘터리는 생존자들에게 목소리를 부여함으로써 카타르시스를 일으켰어요.', example_en_3 = 'She found catharsis in writing about her experiences.', example_ko_3 = '그녀는 자신의 경험을 쓰는 데서 카타르시스를 느꼈어요.', example_en_4 = 'Catharsis is not merely emotional release; it is also cognitive clarification.', example_ko_4 = '카타르시스는 단순한 감정의 발산이 아니라 인지적 명확화이기도 해요.', example_en_5 = 'The final movement of the symphony achieves a profound catharsis.', example_ko_5 = '교향곡의 마지막 악장은 깊은 카타르시스를 이루어요.' WHERE id = 'w_culture_C1_09';

UPDATE words SET example_en_2 = 'The film evokes the sublime through wide shots of the natural landscape.', example_ko_2 = '그 영화는 자연 풍경의 와이드 샷을 통해 숭고함을 불러일으켜요.', example_en_3 = 'Burke defined the sublime as a mixture of terror and awe.', example_ko_3 = '버크는 숭고함을 공포와 경외감의 혼합으로 정의했어요.', example_en_4 = 'She believes music is the art form closest to the sublime.', example_ko_4 = '그녀는 음악이 숭고함에 가장 가까운 예술 형식이라고 믿어요.', example_en_5 = 'The concept of the sublime links aesthetics to moral experience.', example_ko_5 = '숭고함의 개념은 미학과 도덕적 경험을 연결해요.' WHERE id = 'w_culture_C1_10';

UPDATE words SET example_en_2 = 'Aestheticism held that beauty was the highest human achievement.', example_ko_2 = '유미주의는 아름다움이 인간의 가장 높은 성취라고 주장했어요.', example_en_3 = 'The movement of aestheticism rejected the Victorian emphasis on utility.', example_ko_3 = '유미주의 운동은 유용성에 대한 빅토리아 시대의 강조를 거부했어요.', example_en_4 = 'Her work is influenced by aestheticism and symbolist poetry.', example_ko_4 = '그녀의 작품은 유미주의와 상징주의 시의 영향을 받아요.', example_en_5 = 'Aestheticism saw the cultivation of taste as a moral pursuit.', example_ko_5 = '유미주의는 취향의 함양을 도덕적 추구로 봤어요.' WHERE id = 'w_culture_C1_11';

UPDATE words SET example_en_2 = 'The hyperrealism of his portraits makes them look almost photographic.', example_ko_2 = '그의 초상화의 극사실주의적 표현은 거의 사진처럼 보이게 해요.', example_en_3 = 'Hyperrealism in sculpture is even more striking than in painting.', example_ko_3 = '조각에서의 극사실주의는 회화보다 더욱 충격적이에요.', example_en_4 = 'She was drawn to hyperrealism because it challenges what art can represent.', example_ko_4 = '그녀는 예술이 무엇을 표현할 수 있는지에 도전하기 때문에 극사실주의에 끌렸어요.', example_en_5 = 'The museum devoted an entire wing to hyperrealism.', example_ko_5 = '박물관은 전체 날개를 극사실주의에 할애했어요.' WHERE id = 'w_culture_C1_12';

UPDATE words SET example_en_2 = 'The photographer''s work perfectly captured the zeitgeist of post-war Europe.', example_ko_2 = '그 사진작가의 작품은 전후 유럽의 시대정신을 완벽하게 포착했어요.', example_en_3 = 'The fashion designer''s collection mirrored the zeitgeist with remarkable precision.', example_ko_3 = '패션 디자이너의 컬렉션은 시대정신을 놀라운 정확성으로 반영했어요.', example_en_4 = 'Art that captures the zeitgeist often resonates beyond its era.', example_ko_4 = '시대정신을 포착한 예술은 종종 그 시대를 넘어 공명해요.', example_en_5 = 'What is the zeitgeist of the current artistic moment?', example_ko_5 = '현재 예술적 순간의 시대정신은 무엇인가요?' WHERE id = 'w_culture_C1_13';

UPDATE words SET example_en_2 = 'The discourse around contemporary art has become increasingly global.', example_ko_2 = '현대 미술을 둘러싼 담론이 점점 더 글로벌해지고 있어요.', example_en_3 = 'She contributes regularly to the academic discourse on film theory.', example_ko_3 = '그녀는 영화 이론에 관한 학술적 담론에 정기적으로 기여해요.', example_en_4 = 'The curator''s choice of works shaped the discourse of the entire exhibition.', example_ko_4 = '큐레이터의 작품 선택은 전시회 전체의 담론을 형성했어요.', example_en_5 = 'Critical discourse around the novel has shifted substantially over the decades.', example_ko_5 = '소설을 둘러싼 비평적 담론은 수십 년에 걸쳐 크게 변화했어요.' WHERE id = 'w_culture_C1_14';

UPDATE words SET example_en_2 = 'The choir''s polyphony filled the cathedral with extraordinary richness.', example_ko_2 = '합창단의 폴리포니가 성당을 비범한 풍요로움으로 채웠어요.', example_en_3 = 'She spent years studying polyphony in Renaissance sacred music.', example_ko_3 = '그녀는 르네상스 종교 음악의 다성 음악을 공부하는 데 몇 년을 보냈어요.', example_en_4 = 'Polyphony creates a texture in which all voices are equally important.', example_ko_4 = '폴리포니는 모든 성부가 동등하게 중요한 질감을 만들어요.', example_en_5 = 'The piece was remarkable for its complex polyphony and emotional depth.', example_ko_5 = '그 작품은 복잡한 다성 음악과 감정적 깊이로 주목받았어요.' WHERE id = 'w_culture_C1_15';

UPDATE words SET example_en_2 = 'The exhibition celebrated art made in the vernacular traditions of the region.', example_ko_2 = '그 전시회는 지역의 토착 전통에서 만들어진 예술을 기념했어요.', example_en_3 = 'She writes her poetry in the vernacular to reach a wider audience.', example_ko_3 = '그녀는 더 많은 독자에게 닿기 위해 일상 언어로 시를 써요.', example_en_4 = 'Vernacular architecture reflects the practical needs and local materials of a community.', example_ko_4 = '토착 건축은 공동체의 실용적인 필요와 지역 재료를 반영해요.', example_en_5 = 'The artist deliberately chose the vernacular over academic forms of expression.', example_ko_5 = '그 예술가는 의도적으로 학술적 표현 형식보다 일상 언어를 선택했어요.' WHERE id = 'w_culture_C1_16';

UPDATE words SET example_en_2 = 'The film uses the allegory of a crumbling house to represent a failing marriage.', example_ko_2 = '그 영화는 무너지는 집의 우화를 사용해 실패하는 결혼을 표현해요.', example_en_3 = 'She wrote an allegory about the dangers of unchecked power.', example_ko_3 = '그녀는 견제받지 않는 권력의 위험에 관한 우화를 썼어요.', example_en_4 = 'Allegory allows artists to discuss difficult subjects indirectly.', example_ko_4 = '우화는 예술가들이 어려운 주제를 간접적으로 다룰 수 있게 해줘요.', example_en_5 = 'The painting functions as an allegory of the human condition.', example_ko_5 = '그 그림은 인간 조건의 우화로 기능해요.' WHERE id = 'w_culture_C1_17';

UPDATE words SET example_en_2 = 'The trope of the unreliable narrator appears in many postmodern novels.', example_ko_2 = '믿을 수 없는 서술자라는 비유는 많은 포스트모던 소설에 등장해요.', example_en_3 = 'The film subverts the trope of the hero''s journey.', example_ko_3 = '그 영화는 영웅의 여정이라는 비유를 전복시켜요.', example_en_4 = 'She avoids common tropes and always seeks a fresh perspective.', example_ko_4 = '그녀는 일반적인 비유를 피하고 항상 새로운 시각을 추구해요.', example_en_5 = 'A worn-out trope can undermine an otherwise powerful narrative.', example_ko_5 = '진부한 비유는 그 밖에 강력한 서사를 약화시킬 수 있어요.' WHERE id = 'w_culture_C1_18';

UPDATE words SET example_en_2 = 'Questions of canonicity determine which voices are heard and which are silenced.', example_ko_2 = '정전성 문제는 어떤 목소리가 들리고 어떤 목소리가 침묵되는지를 결정해요.', example_en_3 = 'She argued that canonicity is always a product of cultural power.', example_ko_3 = '그녀는 정전성이 항상 문화적 권력의 산물이라고 주장했어요.', example_en_4 = 'The canonicity of certain works is regularly contested by scholars.', example_ko_4 = '특정 작품들의 정전성은 학자들에 의해 정기적으로 논쟁돼요.', example_en_5 = 'Reconsidering canonicity is a central concern of postcolonial criticism.', example_ko_5 = '정전성을 재고하는 것은 포스트식민주의 비평의 핵심적인 관심사예요.' WHERE id = 'w_culture_C1_19';

UPDATE words SET example_en_2 = 'The poet practised ekphrasis by describing a seventeenth-century Dutch painting.', example_ko_2 = '시인은 17세기 네덜란드 그림을 묘사함으로써 에크프라시스를 실천했어요.', example_en_3 = 'Ekphrasis creates a dialogue between visual and verbal art forms.', example_ko_3 = '에크프라시스는 시각적 예술 형식과 언어적 예술 형식 사이의 대화를 만들어요.', example_en_4 = 'She wrote an ekphrasis about a sculpture she had seen in Athens.', example_ko_4 = '그녀는 아테네에서 본 조각품에 관한 에크프라시스를 썼어요.', example_en_5 = 'Ekphrasis is a tradition that goes back to ancient Greek literature.', example_ko_5 = '에크프라시스는 고대 그리스 문학까지 거슬러 올라가는 전통이에요.' WHERE id = 'w_culture_C1_20';

UPDATE words SET example_en_2 = 'The film''s final image is one of quiet but devastating pathos.', example_ko_2 = '그 영화의 마지막 이미지는 조용하지만 충격적인 파토스의 것이에요.', example_en_3 = 'She used close-ups to achieve pathos without melodrama.', example_ko_3 = '그녀는 멜로드라마 없이 파토스를 이루기 위해 클로즈업을 사용했어요.', example_en_4 = 'The pathos of the poem comes from what is left unsaid.', example_ko_4 = '시의 파토스는 말해지지 않은 것에서 비롯돼요.', example_en_5 = 'Without genuine pathos, tragedy collapses into mere spectacle.', example_ko_5 = '진정한 파토스 없이는 비극이 단순한 볼거리로 무너져요.' WHERE id = 'w_culture_C1_21';

UPDATE words SET example_en_2 = 'The ethos of the collective was rooted in collaboration and mutual support.', example_ko_2 = '그 집단의 에토스는 협업과 상호 지원에 뿌리를 두고 있었어요.', example_en_3 = 'The documentary captures the ethos of the punk movement.', example_ko_3 = '그 다큐멘터리는 펑크 운동의 에토스를 포착해요.', example_en_4 = 'Her work embodies an ethos of radical inclusivity.', example_ko_4 = '그녀의 작품은 급진적인 포용성의 에토스를 구현해요.', example_en_5 = 'The gallery''s curatorial ethos is to challenge, not simply display.', example_ko_5 = '갤러리의 큐레이터 에토스는 단순히 전시하는 것이 아니라 도전하는 것이에요.' WHERE id = 'w_culture_C1_22';

UPDATE words SET example_en_2 = 'The essay builds its logos through detailed analysis of primary sources.', example_ko_2 = '그 에세이는 1차 자료의 상세한 분석을 통해 로고스를 구축해요.', example_en_3 = 'In rhetoric, logos appeals to the audience''s reason.', example_ko_3 = '수사학에서 로고스는 청중의 이성에 호소해요.', example_en_4 = 'She balances logos with ethos and pathos in her critical writing.', example_ko_4 = '그녀는 비평 글에서 로고스, 에토스, 파토스를 균형 있게 조화시켜요.', example_en_5 = 'The film relies on emotional appeal rather than logos to make its case.', example_ko_5 = '그 영화는 주장을 펼치기 위해 로고스보다 감정적 호소에 의존해요.' WHERE id = 'w_culture_C1_23';

UPDATE words SET example_en_2 = 'The sculpture is placed in a liminal space between inside and outside.', example_ko_2 = '그 조각품은 내부와 외부 사이의 경계적 공간에 배치돼 있어요.', example_en_3 = 'Liminal moments in theatre are charged with possibility.', example_ko_3 = '연극에서 경계적인 순간은 가능성으로 가득 차 있어요.', example_en_4 = 'Her paintings inhabit a liminal zone between abstraction and figuration.', example_ko_4 = '그녀의 그림은 추상과 구상 사이의 경계적 영역에 위치해 있어요.', example_en_5 = 'The exhibition explores the liminal boundaries of identity and culture.', example_ko_5 = '전시회는 정체성과 문화의 경계적 경계를 탐구해요.' WHERE id = 'w_culture_C1_24';

UPDATE words SET example_en_2 = 'Her polemic against the art market was widely discussed.', example_ko_2 = '예술 시장에 대한 그녀의 논쟁적 글은 널리 논의됐어요.', example_en_3 = 'The documentary is a powerful polemic against cultural erasure.', example_ko_3 = '그 다큐멘터리는 문화 말살에 맞선 강력한 논쟁이에요.', example_en_4 = 'He delivered a polemic that divided the audience entirely.', example_ko_4 = '그는 청중을 완전히 갈라놓은 논쟁적인 발언을 했어요.', example_en_5 = 'The essay is as much a polemic as it is a critical analysis.', example_ko_5 = '그 에세이는 비평적 분석인 만큼이나 논쟁적인 글이에요.' WHERE id = 'w_culture_C1_25';

UPDATE words SET example_en_2 = 'The artist challenges the dominant meta-narrative of progress.', example_ko_2 = '그 예술가는 지배적인 진보의 메타 내러티브에 도전해요.', example_en_3 = 'Postmodernism holds that there is no single meta-narrative capable of explaining everything.', example_ko_3 = '포스트모더니즘은 모든 것을 설명할 수 있는 단일 메타 내러티브가 없다고 주장해요.', example_en_4 = 'Her film deconstructs the meta-narrative of national heroism.', example_ko_4 = '그녀의 영화는 국가적 영웅주의의 메타 내러티브를 해체해요.', example_en_5 = 'Art that questions its own meta-narrative is inherently self-reflexive.', example_ko_5 = '자체 메타 내러티브에 의문을 제기하는 예술은 본질적으로 자기 반성적이에요.' WHERE id = 'w_culture_C1_26';

UPDATE words SET example_en_2 = 'Her synaesthesia allowed her to experience music as a cascade of colours.', example_ko_2 = '그녀의 공감각은 음악을 색채의 연속으로 경험하게 해줬어요.', example_en_3 = 'Synaesthesia is more common among artists and musicians than in the general population.', example_ko_3 = '공감각은 일반 대중보다 예술가와 음악가 사이에서 더 흔해요.', example_en_4 = 'The installation was designed to evoke synaesthesia in its audience.', example_ko_4 = '그 설치물은 관람객에게 공감각을 불러일으키도록 설계됐어요.', example_en_5 = 'Kandinsky''s theory of art was heavily influenced by his synaesthesia.', example_ko_5 = '칸딘스키의 예술 이론은 그의 공감각에 크게 영향을 받았어요.' WHERE id = 'w_culture_C1_27';

UPDATE words SET example_en_2 = 'The artist defended his appropriation of advertising imagery as commentary.', example_ko_2 = '그 예술가는 광고 이미지의 전용을 논평으로 옹호했어요.', example_en_3 = 'Cultural appropriation in fashion has sparked significant debate.', example_ko_3 = '패션에서의 문화 전용은 상당한 논쟁을 촉발했어요.', example_en_4 = 'Appropriation art questions authorship and originality.', example_ko_4 = '전용 예술은 저작권과 독창성에 의문을 제기해요.', example_en_5 = 'She examines appropriation as both a creative strategy and an ethical problem.', example_ko_5 = '그녀는 전용을 창조적 전략이자 윤리적 문제로 검토해요.' WHERE id = 'w_culture_C1_28';

UPDATE words SET example_en_2 = 'The exhibition challenged Western hegemony in the global art market.', example_ko_2 = '그 전시회는 글로벌 예술 시장에서의 서구 헤게모니에 도전했어요.', example_en_3 = 'She argues that cultural hegemony is reproduced through museum collections.', example_ko_3 = '그녀는 문화적 헤게모니가 박물관 컬렉션을 통해 재생산된다고 주장해요.', example_en_4 = 'Gramsci''s concept of hegemony is central to cultural studies.', example_ko_4 = '그람시의 헤게모니 개념은 문화 연구의 핵심이에요.', example_en_5 = 'Resisting cultural hegemony requires both awareness and active counter-practice.', example_ko_5 = '문화적 헤게모니에 저항하려면 인식과 능동적인 반실천 모두가 필요해요.' WHERE id = 'w_culture_C1_29';

UPDATE words SET example_en_2 = 'The biennial celebrates the plurality of artistic approaches across cultures.', example_ko_2 = '비엔날레는 문화 전반에 걸친 예술적 접근 방식의 다원성을 기념해요.', example_en_3 = 'Plurality within a single artwork creates multiple simultaneous meanings.', example_ko_3 = '단일 예술 작품 내의 다원성은 동시에 여러 의미를 만들어요.', example_en_4 = 'She advocates for cultural plurality over a unified national narrative.', example_ko_4 = '그녀는 통일된 국가 서사보다 문화적 다원성을 옹호해요.', example_en_5 = 'The festival''s plurality makes it impossible to reduce to a single theme.', example_ko_5 = '축제의 다원성은 단일 주제로 축소하기 불가능하게 해요.' WHERE id = 'w_culture_C1_30';

UPDATE words SET example_en_2 = 'The meaning of the work is marked by contingency rather than fixed intention.', example_ko_2 = '그 작품의 의미는 고정된 의도가 아니라 우연성으로 특징지어져요.', example_en_3 = 'Historical contingency explains why certain artists rose to prominence.', example_ko_3 = '역사적 우연성은 왜 특정 예술가들이 두각을 나타냈는지를 설명해요.', example_en_4 = 'The performance embraces contingency by including audience participation.', example_ko_4 = '그 공연은 관객 참여를 포함함으로써 우연성을 받아들여요.', example_en_5 = 'Acknowledging contingency is essential to honest cultural criticism.', example_ko_5 = '우연성을 인정하는 것은 솔직한 문화 비평에 필수적이에요.' WHERE id = 'w_culture_C1_31';

UPDATE words SET example_en_2 = 'Reflexivity in filmmaking means the camera acknowledges its own presence.', example_ko_2 = '영화 제작에서의 반성성은 카메라가 자신의 존재를 인정하는 것을 의미해요.', example_en_3 = 'She brings reflexivity to her practice by questioning her own assumptions.', example_ko_3 = '그녀는 자신의 가정에 의문을 제기함으로써 실천에 반성성을 가져와요.', example_en_4 = 'Reflexivity is a hallmark of ethnographic and documentary approaches.', example_ko_4 = '반성성은 민족지학적 및 다큐멘터리 접근 방식의 특징이에요.', example_en_5 = 'The novel''s reflexivity foregrounds the act of writing itself.', example_ko_5 = '그 소설의 반성성은 글쓰기 행위 자체를 전면에 내세워요.' WHERE id = 'w_culture_C1_32';

UPDATE words SET example_en_2 = 'The transmedial story world spans novels, films, and video games.', example_ko_2 = '트랜스미디어 이야기 세계는 소설, 영화, 비디오 게임에 걸쳐 있어요.', example_en_3 = 'Transmedial storytelling offers audiences different entry points into the same world.', example_ko_3 = '트랜스미디어 스토리텔링은 관객에게 같은 세계로 들어가는 다양한 진입점을 제공해요.', example_en_4 = 'She studies transmedial narratives as a form of participatory culture.', example_ko_4 = '그녀는 트랜스미디어 서사를 참여 문화의 한 형태로 연구해요.', example_en_5 = 'A transmedial approach requires coordination across many creative teams.', example_ko_5 = '트랜스미디어 접근 방식은 여러 창작 팀 간의 조율이 필요해요.' WHERE id = 'w_culture_C1_33';

UPDATE words SET example_en_2 = 'The voice-over narration exists outside the diegesis of the film.', example_ko_2 = '보이스오버 내레이션은 영화의 디에게시스 밖에 존재해요.', example_en_3 = 'Events within the diegesis are experienced by the characters directly.', example_ko_3 = '디에게시스 내의 사건들은 등장인물들이 직접 경험해요.', example_en_4 = 'The film disrupts its own diegesis by having a character address the camera.', example_ko_4 = '그 영화는 등장인물이 카메라에 말을 건네게 함으로써 자체 디에게시스를 방해해요.', example_en_5 = 'Music within the diegesis is heard by the characters; music outside is not.', example_ko_5 = '디에게시스 안의 음악은 등장인물들이 들을 수 있고, 밖의 음악은 그렇지 않아요.' WHERE id = 'w_culture_C1_34';

UPDATE words SET example_en_2 = 'The bricoleur works with whatever materials are at hand rather than ordering specific supplies.', example_ko_2 = '브리콜뢰르는 특정 재료를 주문하기보다 손에 있는 재료로 작업해요.', example_en_3 = 'She describes her creative process as that of a bricoleur.', example_ko_3 = '그녀는 자신의 창작 과정을 브리콜뢰르의 것으로 묘사해요.', example_en_4 = 'Lévi-Strauss contrasted the bricoleur with the engineer in his analysis of myth.', example_ko_4 = '레비스트로스는 신화 분석에서 브리콜뢰르를 공학자와 대비했어요.', example_en_5 = 'As a cultural bricoleur, he draws from history, tradition, and popular media alike.', example_ko_5 = '문화적 브리콜뢰르로서 그는 역사, 전통, 대중 미디어를 모두 활용해요.' WHERE id = 'w_culture_C1_35';

